import sys

def is_valid(s, t_prime):
    len_s = len(s)
    len_t = len(t_prime)

    # Check if lengths differ by more than 1
    if abs(len_s - len_t) > 1:
        return False

    # Case 1: Same length (could be one edit: replace or same)
    if len_s == len_t:
        diff = 0
        for a, b in zip(s, t_prime):
            if a != b:
                diff += 1
                if diff > 1:
                    return False
        return diff <= 1

    # Case 2: s is longer by 1 (could be insert in t_prime)
    elif len_s == len_t + 1:
        i = 0
        j = 0
        diff = 0
        while i < len_s and j < len_t:
            if s[i] == t_prime[j]:
                i += 1
                j += 1
            else:
                i += 1
                diff += 1
                if diff > 1:
                    return False
        return True

    # Case 3: s is shorter by 1 (could be delete in t_prime)
    elif len_s == len_t - 1:
        i = 0
        j = 0
        diff = 0
        while i < len_s and j < len_t:
            if s[i] == t_prime[j]:
                i += 1
                j += 1
            else:
                j += 1
                diff += 1
                if diff > 1:
                    return False
        return True

    return False

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    T_prime = input[1]
    S_list = input[2:]

    result = []
    for idx, s in enumerate(S_list, 1):
        if is_valid(s, T_prime):
            result.append(idx)

    print(len(result))
    if result:
        print(' '.join(map(str, result)))

if __name__ == "__main__":
    main()
